<template>
  <div>
    <ModuleTable title="品牌管理" description="维护品牌租户、标识、Logo、商品标识和启停状态。" :columns="columns" :rows="brands" :keyword-fields="['code','name']" secondary-action-text="导出品牌" danger-action-text="禁用" row-action-text="修改" />
