<script setup lang="ts">
import { reactive, ref } from 'vue'; import { ElMessage, type FormInstance, type FormRules } from 'element-plus'; import ModuleTable from '@/components/business/ModuleTable.vue'; import { brands, statusMaps } from '@/mock/modules/module-data'; import type { TableColumnConfig } from '@/types/module'
const dialogVisible=ref(false); const submitLoading=ref(false); const formRef=ref<FormInstance>(); const form=reactive({tenant:'D0174',name:'',code:'',pieceBilling:false,mergeUser:false,shoeTag:'',luxuryTag:'',repairTag:'',smallTag:'',otherTag:'',cancelBlock:'',meituanVerify:'',status:'enabled',remark:''}); const rules:FormRules={tenant:[{required:true,message:'请选择租户',trigger:'change'}],name:[{required:true,message:'请输入名称',trigger:'blur'}],code:[{required:true,message:'请输入标识',trigger:'blur'}],cancelBlock:[{required:true,message:'请选择工厂取消拦截',trigger:'change'}],meituanVerify:[{required:true,message:'请选择美团核销时间',trigger:'change'}],status:[{required:true,message:'请选择状态',trigger:'change'}]}
const columns: TableColumnConfig[]=[{prop:'code',label:'ID',width:130},{prop:'name',label:'名称',minWidth:160},{prop:'merchantCount',label:'商户数',width:100,type:'number'},{prop:'productCount',label:'商品数',width:100,type:'number'},{prop:'status',label:'状态',width:100,type:'status',statusMap:statusMaps.enabled},{prop:'updatedAt',label:'修改时间',width:130}]
async function submit(){ if(submitLoading.value)return; await formRef.value?.validate(); submitLoading.value=true; try{ await new Promise(r=>setTimeout(r,650)); ElMessage.success('品牌保存成功'); dialogVisible.value=false } finally{ submitLoading.value=false } }
</script>
